// // This module is designed to decrement a 3-bit down counter on the rising edge of a clock signal. Upon receiving a reset signal (rst), the counter resets its value to seven. The current count value is output as a 3-bit wide signal, allowing it to count from 7 to 0.
module top_module(
		input  wire  clk,
		input  wire  rst,
		output reg   [2:0] count
	);reg [2:0] reg_count;

	always @(posedge clk) begin
		if (rst) begin
			reg_count <= 3'b0;
		end else begin
			reg_count <= reg_count + 1;
		end
	end

	assign count = reg_count;

endmodule
